/**
 * PPTX/PPT to Images Converter
 * Converte apresentações em imagens de slide usando LibreOffice headless + pdftoppm
 *
 * Pipeline:
 *   1. PPTX → PDF via soffice --headless --convert-to pdf
 *   2. PDF → PNGs via pdftoppm (poppler-utils)
 *
 * Se LibreOffice ou pdftoppm não estiverem disponíveis, retorna erro descritivo.
 */

import { execFile } from 'child_process';
import { promisify } from 'util';
import { promises as fs } from 'fs';
import * as path from 'path';
import { logger } from '@lib/logger';

const execFileAsync = promisify(execFile);

export interface SlideImage {
  slideNumber: number;
  imagePath: string;
  width: number;
  height: number;
}

export interface ConversionResult {
  success: boolean;
  images: SlideImage[];
  totalSlides: number;
  error?: string;
}

export interface ConversionOptions {
  /** Output image width in pixels (default: 1920) */
  width?: number;
  /** Output image height in pixels (default: 1080) */
  height?: number;
  /** DPI for rendering (default: 150) */
  dpi?: number;
  /** Output format: 'png' or 'jpeg' (default: 'png') */
  format?: 'png' | 'jpeg';
  /** Custom output directory (auto-created if not exists) */
  outputDir?: string;
  /** Timeout for LibreOffice conversion in ms (default: 120000) */
  timeoutMs?: number;
}

const DEFAULT_OPTIONS: Required<ConversionOptions> = {
  width: 1920,
  height: 1080,
  dpi: 150,
  format: 'png',
  outputDir: '',
  timeoutMs: 120_000,
};

/**
 * Verifica se um binário está disponível no PATH
 */
async function isBinaryAvailable(binary: string): Promise<boolean> {
  try {
    await execFileAsync('which', [binary]);
    return true;
  } catch {
    return false;
  }
}

/**
 * Detecta o caminho do binário do LibreOffice
 */
async function findLibreOfficeBinary(): Promise<string | null> {
  const candidates = ['soffice', 'libreoffice', '/usr/bin/soffice', '/usr/bin/libreoffice'];
  for (const bin of candidates) {
    if (await isBinaryAvailable(bin)) {
      return bin;
    }
  }
  return null;
}

/**
 * Converte PPTX/PPT para PDF usando LibreOffice headless
 */
async function convertToPdf(
  inputPath: string,
  outputDir: string,
  soffice: string,
  timeoutMs: number
): Promise<string> {
  const args = [
    '--headless',
    '--invisible',
    '--nologo',
    '--nofirststartwizard',
    '--convert-to', 'pdf',
    '--outdir', outputDir,
    inputPath,
  ];

  logger.info('[PPTX→Images] Converting to PDF via LibreOffice', {
    component: 'PPTXToImages',
    input: path.basename(inputPath),
    soffice,
  });

  try {
    const { stdout, stderr } = await execFileAsync(soffice, args, {
      timeout: timeoutMs,
      maxBuffer: 10 * 1024 * 1024, // 10MB
    });

    if (stderr && stderr.length > 0) {
      logger.warn('[PPTX→Images] LibreOffice stderr output', {
        component: 'PPTXToImages',
        stderr: stderr.substring(0, 500),
      });
    }

    // LibreOffice outputs a PDF with the same base name
    const baseName = path.basename(inputPath, path.extname(inputPath));
    const pdfPath = path.join(outputDir, `${baseName}.pdf`);

    // Verify the PDF was created
    try {
      await fs.access(pdfPath);
    } catch {
      throw new Error(
        `LibreOffice did not produce expected PDF at ${pdfPath}. stdout: ${stdout?.substring(0, 200)}`
      );
    }

    return pdfPath;
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    if (msg.includes('ETIMEDOUT') || msg.includes('timeout')) {
      throw new Error(`LibreOffice conversion timed out after ${timeoutMs}ms`);
    }
    throw new Error(`LibreOffice conversion failed: ${msg}`);
  }
}

/**
 * Converte PDF para imagens PNG usando pdftoppm (poppler-utils)
 */
async function convertPdfToImages(
  pdfPath: string,
  outputDir: string,
  options: Required<ConversionOptions>
): Promise<string[]> {
  const outputPrefix = path.join(outputDir, 'slide');
  const formatFlag = options.format === 'jpeg' ? '-jpeg' : '-png';

  const args = [
    formatFlag,
    '-r', String(options.dpi),
    '-scale-to-x', String(options.width),
    '-scale-to-y', String(options.height),
    pdfPath,
    outputPrefix,
  ];

  logger.info('[PPTX→Images] Converting PDF to images via pdftoppm', {
    component: 'PPTXToImages',
    dpi: options.dpi,
    format: options.format,
    width: options.width,
    height: options.height,
  });

  try {
    await execFileAsync('pdftoppm', args, {
      timeout: options.timeoutMs,
      maxBuffer: 10 * 1024 * 1024,
    });
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    throw new Error(`pdftoppm conversion failed: ${msg}`);
  }

  // pdftoppm outputs files like: slide-01.png, slide-02.png, ...
  const ext = options.format === 'jpeg' ? 'jpg' : 'png';
  const files = await fs.readdir(outputDir);
  const imageFiles = files
    .filter(f => f.startsWith('slide-') && f.endsWith(`.${ext}`))
    .sort((a, b) => {
      const numA = parseInt(a.replace(/\D/g, ''), 10);
      const numB = parseInt(b.replace(/\D/g, ''), 10);
      return numA - numB;
    });

  return imageFiles.map(f => path.join(outputDir, f));
}

/**
 * Converte um arquivo PPTX/PPT em imagens individuais de cada slide.
 *
 * Requer LibreOffice (soffice) e pdftoppm (poppler-utils) instalados no sistema.
 *
 * @param inputPath - Caminho absoluto do arquivo .pptx ou .ppt
 * @param options - Opções de conversão (resolução, formato, etc.)
 * @returns Resultado com array de imagens ordenadas por slide
 */
export async function convertPresentationToImages(
  inputPath: string,
  options?: ConversionOptions
): Promise<ConversionResult> {
  const opts: Required<ConversionOptions> = { ...DEFAULT_OPTIONS, ...options };

  // Validate input file exists
  try {
    await fs.access(inputPath);
  } catch {
    return {
      success: false,
      images: [],
      totalSlides: 0,
      error: `Input file not found: ${inputPath}`,
    };
  }

  // Check LibreOffice availability
  const soffice = await findLibreOfficeBinary();
  if (!soffice) {
    logger.error('[PPTX→Images] LibreOffice (soffice) not found in PATH', new Error('LibreOffice not installed'), {
      component: 'PPTXToImages',
    });
    return {
      success: false,
      images: [],
      totalSlides: 0,
      error:
        'LibreOffice is not installed or not in PATH. Install with: apt-get install libreoffice-impress (Debian/Ubuntu) or brew install --cask libreoffice (macOS)',
    };
  }

  // Check pdftoppm availability
  const hasPdftoppm = await isBinaryAvailable('pdftoppm');
  if (!hasPdftoppm) {
    logger.error('[PPTX→Images] pdftoppm not found in PATH', new Error('pdftoppm not installed'), {
      component: 'PPTXToImages',
    });
    return {
      success: false,
      images: [],
      totalSlides: 0,
      error:
        'pdftoppm (poppler-utils) is not installed. Install with: apt-get install poppler-utils (Debian/Ubuntu) or brew install poppler (macOS)',
    };
  }

  // Create output directory
  const outputDir =
    opts.outputDir || path.join(path.dirname(inputPath), `slides_${Date.now()}`);
  await fs.mkdir(outputDir, { recursive: true });

  try {
    // Step 1: Convert PPTX to PDF
    const pdfPath = await convertToPdf(inputPath, outputDir, soffice, opts.timeoutMs);

    // Step 2: Convert PDF to images
    const imagePaths = await convertPdfToImages(pdfPath, outputDir, opts);

    if (imagePaths.length === 0) {
      return {
        success: false,
        images: [],
        totalSlides: 0,
        error: 'No slide images were generated. The presentation may be empty.',
      };
    }

    // Build result with slide metadata
    const images: SlideImage[] = imagePaths.map((imgPath, index) => ({
      slideNumber: index + 1,
      imagePath: imgPath,
      width: opts.width,
      height: opts.height,
    }));

    logger.info('[PPTX→Images] Conversion complete', {
      component: 'PPTXToImages',
      totalSlides: images.length,
      outputDir,
    });

    // Clean up intermediate PDF
    try {
      await fs.unlink(pdfPath);
    } catch {
      // Non-critical: PDF cleanup failure is not an error
    }

    return {
      success: true,
      images,
      totalSlides: images.length,
    };
  } catch (error: unknown) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    logger.error('[PPTX→Images] Conversion failed', error instanceof Error ? error : new Error(errorMessage), {
      component: 'PPTXToImages',
      input: path.basename(inputPath),
    });

    return {
      success: false,
      images: [],
      totalSlides: 0,
      error: errorMessage,
    };
  }
}

/**
 * Verifica se o sistema tem os requisitos para conversão de apresentações
 */
export async function checkConversionDependencies(): Promise<{
  libreoffice: boolean;
  pdftoppm: boolean;
  ready: boolean;
  message: string;
}> {
  const libreoffice = (await findLibreOfficeBinary()) !== null;
  const pdftoppm = await isBinaryAvailable('pdftoppm');
  const ready = libreoffice && pdftoppm;

  let message = 'All dependencies available';
  if (!ready) {
    const missing: string[] = [];
    if (!libreoffice) missing.push('libreoffice');
    if (!pdftoppm) missing.push('poppler-utils (pdftoppm)');
    message = `Missing dependencies: ${missing.join(', ')}`;
  }

  return { libreoffice, pdftoppm, ready, message };
}
